// =====================================================
// Post-processor HTML opisów produktów
// =====================================================
// Czyści output AI Agent z artefaktów webSearch (cytaty),
// akceptuje URL-e zdjęć pochodzące z pól s_photo_* (dowolne źródło),
// waliduje strukturę 3-sekcyjną.
// =====================================================

// --- 1. Pobierz dane wejściowe ---
const html = $input.first().json.output || '';
const row = $('Get row(s)').item.json;

// [ZMIANA] normalizacja: wymuś https, przytnij, odrzuć nie-URL
const normalizeUrl = (u) => {
  if (!u || typeof u !== 'string') return null;
  const s = u.trim();
  if (!/^https?:\/\//i.test(s)) return null;
  return s.replace(/^http:\/\//i, 'https://');
};

// [ZMIANA] pula + zbiór dozwolonych = dokładnie zdjęcia z s_photo_* tego wiersza
const photoUrls = [];
const allowed = new Set();
for (let i = 1; i <= 16; i++) {
  const u = normalizeUrl(row[`s_photo_${i}`]);
  if (u && !allowed.has(u)) { allowed.add(u); photoUrls.push(u); }
}

// --- 2. Funkcja czyszcząca ---
function cleanProductHtml(html, photoUrls, allowed) {
  if (!html || typeof html !== 'string') {
    return { output: '', warnings: ['empty_input'], validation: {} };
  }

  const warnings = [];
  const validation = {
    citationsRemoved: 0,
    externalImagesReplaced: 0,
    externalImagesRemoved: 0,
    forbiddenTagsRemoved: 0,
    markdownWrappersStripped: 0,
  };

  let cleaned = html;

  // (1) Strip markdown code fences ```html ... ```
  const mdFenceRegex = /^\s*```(?:html|markdown)?\s*\n?|\n?\s*```\s*$/g;
  const beforeFence = cleaned.length;
  cleaned = cleaned.replace(mdFenceRegex, '');
  if (cleaned.length !== beforeFence) validation.markdownWrappersStripped++;

  // (2) Remove OpenAI inline citations: ([domain.com](url))
  const citationRegex = /\s*\(\[[^\]]+\]\(https?:\/\/[^)]+\)\)/g;
  const citMatches = cleaned.match(citationRegex);
  if (citMatches) {
    validation.citationsRemoved = citMatches.length;
    cleaned = cleaned.replace(citationRegex, '');
  }

  // (3) Catch any remaining markdown links [text](url) → text
  const mdLinkRegex = /\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g;
  const mdLinkMatches = cleaned.match(mdLinkRegex);
  if (mdLinkMatches) {
    warnings.push(`removed_${mdLinkMatches.length}_markdown_links`);
    cleaned = cleaned.replace(mdLinkRegex, '$1');
  }

  // (4) [ZMIANA] Filtr <img>: zostaw jeśli src jest wśród zdjęć z s_photo_*, inaczej podmień/wytnij
  let imgIdx = 0;
  cleaned = cleaned.replace(/<img\b[^>]*>/gi, (imgTag) => {
    const srcMatch = imgTag.match(/\bsrc\s*=\s*["']([^"']+)["']/i);
    const src = normalizeUrl(srcMatch ? srcMatch[1] : '');

    // znany URL (z inputu) → zostaw, wymuszając https w samym tagu
    if (src && allowed.has(src)) {
      return imgTag.replace(/\bsrc\s*=\s*["'][^"']+["']/i, `src="${src}"`);
    }

    // nieznany / halucynowany → podmień na realny z puli
    if (photoUrls.length > 0) {
      const replacement = photoUrls[imgIdx % photoUrls.length];
      imgIdx++;
      validation.externalImagesReplaced++;
      const altMatch = imgTag.match(/\balt\s*=\s*["']([^"']*)["']/i);
      const alt = altMatch ? altMatch[1] : 'zdjęcie produktu';
      return `<img src="${replacement}" alt="${alt}">`;
    }

    validation.externalImagesRemoved++;
    return '';
  });

  // (5) Strip empty <div></div>
  cleaned = cleaned.replace(/<div>\s*<\/div>/g, '');
  cleaned = cleaned.replace(/<div>\s*\n?\s*<\/div>/g, '');

// (1b) Normalizacja cala -> ″ (łapie też encję &quot; / &#34;)
  cleaned = cleaned
    .replace(/(\d)\s*(?:&quot;|&#0*34;)/gi, '$1″')  // 10&quot; -> 10″
    .replace(/(\d)\s*["""'']{2,}/g, '$1″')          // 10"" / 10'' -> 10″
    .replace(/(\d)\s*["""]/g, '$1″');                // 10" -> 10″

  // (6) Convert h1/h3/h4/h5/h6 → <p><strong>
  ['h1', 'h3', 'h4', 'h5', 'h6'].forEach(tag => {
    const openRegex = new RegExp(`<${tag}\\b[^>]*>`, 'gi');
    const closeRegex = new RegExp(`<\\/${tag}>`, 'gi');
    if (openRegex.test(cleaned)) {
      validation.forbiddenTagsRemoved++;
      cleaned = cleaned.replace(openRegex, '<p><strong>');
      cleaned = cleaned.replace(closeRegex, '</strong></p>');
    }
  });

  // (7) Remove <script>, <iframe>, <style>, <link>
  ['script', 'iframe', 'style', 'link'].forEach(tag => {
    const fullRegex = new RegExp(`<${tag}\\b[^>]*>[\\s\\S]*?<\\/${tag}>`, 'gi');
    const selfRegex = new RegExp(`<${tag}\\b[^>]*\\/?>`, 'gi');
    if (fullRegex.test(cleaned) || selfRegex.test(cleaned)) {
      validation.forbiddenTagsRemoved++;
      cleaned = cleaned.replace(fullRegex, '');
      cleaned = cleaned.replace(selfRegex, '');
    }
  });

  cleaned = cleaned.trim();

  // (8) Validation
  const h2Count = (cleaned.match(/<h2\b/gi) || []).length;
  validation.sectionCount = h2Count;
  if (h2Count !== 3) warnings.push(`section_count_${h2Count}_expected_3`);

  validation.length = cleaned.length;
  if (cleaned.length < 4000) warnings.push(`too_short_${cleaned.length}`);
  if (cleaned.length > 5500) warnings.push(`too_long_${cleaned.length}`);

  if (!/^<div\s+class\s*=\s*["']styleDlaOpisuProduktu["']/i.test(cleaned)) {
    warnings.push('missing_root_wrapper');
  }

  validation.finalImageCount = (cleaned.match(/<img\b/gi) || []).length;

  // [ZMIANA] leak-check: każdy <img> którego src NIE ma w allowed
  const leaked = (cleaned.match(/<img\b[^>]*>/gi) || []).filter(tag => {
    const m = tag.match(/\bsrc\s*=\s*["']([^"']+)["']/i);
    return !(m && allowed.has(normalizeUrl(m[1])));
  });
  if (leaked.length) warnings.push(`leaked_external_imgs_${leaked.length}`);

  return { output: cleaned, warnings, validation };
}

// --- 3. Wykonaj czyszczenie ---
const result = cleanProductHtml(html, photoUrls, allowed);

// --- 4. Zwróć w formacie n8n ---
return [{
  json: {
    output: result.output,
    warnings: result.warnings,
    validation: result.validation,
    originalLength: html.length,
    cleanedLength: result.output.length,
    reductionPct: ((1 - result.output.length / html.length) * 100).toFixed(1) + '%',
    productName: row.s_product_name || '',
    productId: row.s_product_id || '',
  }
}];

// === WALIDACJA / KOERCJA STRUCTURED OUTPUT ===
const defs = JSON.parse($('Build Schema').first().json._paramsDef);
const ai = ($json.output && typeof $json.output === 'object') ? $json.output : ($json || {});

const params = {}; let filled = 0, nulled = 0; const warnings = [];

for (const d of defs) {
  let v = ai[d.name];
  if (v === undefined) v = null;
  if (typeof v === 'string') { v = v.trim(); if (v === '' || /^(null|n\/a|brak|nieznany|-)$/i.test(v)) v = null; }

  if (v !== null && d.type === 'number') {
    const n = Number(String(v).replace(',', '.').replace(/[^0-9.\-]/g, ''));
    v = Number.isFinite(n) ? n : null;
  }
  if (v !== null && d.type === 'enum') {
    if (!d.options.includes(v)) { warnings.push('enum_odrzucony:'+d.name+'='+v); v = null; }
  }
  params[d.name] = v;
  if (v === null) nulled++; else filled++;
}

return [{ json: {
  id: $('Get row(s)3').first().json.id,
  params,
  paramsJson: JSON.stringify(params, null, 2),
  _group: $('Build Schema').first().json._group,
  _groupRaw: $('Build Schema').first().json._groupRaw,
  _fallbackEmpty: $('Build Schema').first().json._fallbackEmpty,
  _filled: filled,
  _nulled: nulled,
  _warnings: warnings
}}];

